@while ($remainder > 0 and $precision >= 0) {
  $quotient: 0;
  @while ($remainder >= $divisor) {
    $remainder: $remainder - $divisor;
    $quotient: $quotient + 1;
  }
  $result: $result * 10 + $quotient;
  $factor: $factor * 0.1;
  $remainder: $remainder * 10;
  $precision: $precision - 1;
  @if ($precision < 0 and $remainder >= $divisor * 5) {
    $result: $result + 1;
  }
}

@mixin zap($img) {
    position: relative;

    &::after {
        background-image: url('#{$img}');
        background-repeat: no-repeat;
        background-size: 100% 100%;
        content: '';
        display: block;
        height: 0.3em;
        left: -0.2em;
        position: absolute;
        top: calc(100% - 0.15em);
        width: calc(100% + 0.4em);
    }
}

@each $name, $color in $theme-colors {
  .toast-#{$name} {
    --#{$prefix}toast-header-color: #{color-contrast($color)};
    --#{$prefix}toast-header-bg: #{$color};
    --#{$prefix}toast-header-border-color: #{$color};
    --#{$prefix}toast-border-color: #{$color};
    --#{$prefix}toast-bg: var(--#{$prefix}#{$name}-bg-subtle);

    @if color-contrast($color) == $color-contrast-light {
      .btn-close {
        @include btn-close-white();
      }
    }
  }
}

@for $i from 0 through 12 {
  .#{iv.$class-prefix}columns.#{iv.$class-prefix}is-mobile
    > &.#{iv.$class-prefix}is-#{$i} {
    flex: none;
    width: math.percentage(math.div($i, 12));
  }

  .#{iv.$class-prefix}columns.#{iv.$class-prefix}is-mobile
    > &.#{iv.$class-prefix}is-offset-#{$i} {
    margin-inline-start: math.percentage(math.div($i, 12));
  }
}

@mixin make-row($gutter: $grid-gutter-width) {
  --#{$prefix}gutter-x: #{$gutter};
  --#{$prefix}gutter-y: 0;
  display: flex;
  flex-wrap: wrap;
  // TODO: Revisit calc order after https://github.com/react-bootstrap/react-bootstrap/issues/6039 is fixed
  margin-top: calc(-1 * var(--#{$prefix}gutter-y)); // stylelint-disable-line function-disallowed-list
  margin-right: calc(-.5 * var(--#{$prefix}gutter-x)); // stylelint-disable-line function-disallowed-list
  margin-left: calc(-.5 * var(--#{$prefix}gutter-x)); // stylelint-disable-line function-disallowed-list
}

@each $name, $color in $theme-colors {
  .card-#{$name},
  .bg-#{$name},
  .text-bg-#{$name} {
    --#{$lte-prefix}card-variant-bg: #{$color};
    --#{$lte-prefix}card-variant-bg-rgb: #{to-rgb($color)};
    --#{$lte-prefix}card-variant-color: #{color-contrast($color)};
    --#{$lte-prefix}card-variant-color-rgb: #{to-rgb(color-contrast($color))};
  }
}

&:focus,
  &:focus-within,
  &.#{iv.$class-prefix}is-focused {
    border-color: hsl(
      cv.getVar("input-focus-h"),
      cv.getVar("input-focus-s"),
      cv.getVar("input-focus-l")
    );
    box-shadow: cv.getVar("input-focus-shadow-size")
      hsla(
        cv.getVar("input-focus-h"),
        cv.getVar("input-focus-s"),
        cv.getVar("input-focus-l"),
        cv.getVar("input-focus-shadow-alpha")
      );
  }

// Local docs variables
$bd-purple: #4c0bce;
$bd-violet: lighten(saturate($bd-purple, 5%), 15%);
$bd-accent: #ffe484;
$bd-gutter-x: 3rem;

:root {
  --bd-purple: #{$bd-purple};
  --bd-violet: #{$bd-violet};
  --bd-accent: #{$bd-accent};
  --bd-violet-rgb: #{to-rgb($bd-violet)};
  --bd-accent-rgb: #{to-rgb($bd-accent)};
  --bd-pink-rgb: #{to-rgb($pink-500)};
  --bd-teal-rgb: #{to-rgb($teal-500)};
}

// Material Design Card
// --------------------------------------------------

:host {
  --background: #{$card-md-background};
  --color: #{$card-md-color};

  @include margin($card-md-margin-top, $card-md-margin-end, $card-md-margin-bottom, $card-md-margin-start);
  @include border-radius($card-md-border-radius);

  font-size: $card-md-font-size;

  box-shadow: $card-md-box-shadow;
}

> a,
    > span {
      display: block;
      padding: $spacing-x-small $spacing-small;

      &:hover {
        background-color: var(--slds-g-color-neutral-base-95, #{$color-background-row-hover});
        cursor: pointer;
      }

      &:active {
        background-color: var(--slds-g-color-neutral-base-95, #{$color-background-row-active});
      }
    }

&.#{iv.$class-prefix}are-medium {
  .#{iv.$class-prefix}tag:not(.#{iv.$class-prefix}is-normal):not(
      .#{iv.$class-prefix}is-large
    ) {
    font-size: cv.getVar("size-normal");
  }
}

&.#{iv.$class-prefix}are-large {
  .#{iv.$class-prefix}tag:not(.#{iv.$class-prefix}is-normal):not(
      .#{iv.$class-prefix}is-medium
    ) {
    font-size: cv.getVar("size-medium");
  }
}

& + .#{iv.$class-prefix}media {
  border-top-color: cv.getVar("media-border-color");
  border-top-style: solid;
  border-top-width: cv.getVar("media-border-size");
  margin-top: cv.getVar("media-spacing");
  padding-top: cv.getVar("media-spacing");
}

// Sizes
&.#{iv.$class-prefix}is-large {
  & + .#{iv.$class-prefix}media {
    margin-top: cv.getVar("media-spacing-large");
    padding-top: cv.getVar("media-spacing-large");
  }
}

align-items: center;
  background-color: hsl(
    cv.getVar("tag-h"),
    cv.getVar("tag-s"),
    calc(
      #{cv.getVar("tag-background-l")} + #{cv.getVar("tag-background-l-delta")}
    )
  );
  border-radius: $tag-radius;
  color: hsl(cv.getVar("tag-h"), cv.getVar("tag-s"), cv.getVar("tag-color-l"));
  display: inline-flex;
  font-size: cv.getVar("size-small");
  height: 2em;
  justify-content: center;

~ .slds-checkbox_faux,
      ~ .slds-checkbox--faux,
      + .slds-checkbox_faux,
      + .slds-checkbox--faux {
        background-color: var(--slds-g-color-neutral-base-95, #{$color-background-button-brand-disabled});
        border-color: var(--slds-g-color-neutral-base-80, #{$color-border-button-brand-disabled});
        color: var(--slds-g-color-neutral-base-100, #{$color-text-button-brand-disabled});
        cursor: default;

        &:before,
        &:after {
          background: var(--slds-g-color-neutral-base-60, #{$color-gray-8});
        }
      }

&:before {
  content: '';
  position: absolute;
  top: 0;
  right: 0;
  bottom: 0;
  left: 0;
  background: linear-gradient(to top, var(--slds-g-color-neutral-base-10, rgba(0, 0, 0, 1)), var(--slds-g-color-neutral-10-opacity-75, rgba(0, 0, 0, 0.9)) 1%, transparent 99%),
    linear-gradient(to right, var(--slds-g-color-neutral-base-100, rgba(255, 255, 255, 1)) 1%, transparent);
}

&[disabled] ~ .slds-file-selector__body {
  color: var(--slds-g-color-neutral-base-50, #{$color-text-button-default-disabled});

  > .slds-file-selector__button {
    background: var(--slds-g-color-neutral-base-95, #{$color-background-button-brand-disabled});
    border-color: var(--slds-g-color-neutral-base-80, #{$color-border-button-brand-disabled});
    color: var(--slds-g-color-neutral-base-50, #{$color-text-button-brand-disabled});
  }

  > .slds-file-selector__body-icon {
    fill: currentColor;
  }
}

&.slds-is-active .slds-progress__marker {
  box-shadow: var(--slds-g-color-neutral-base-100, #{$progress-color-background}) 0 0 0 4px; // Adds whitespace around indicator

  &:hover,
  &:focus {
    border-color: var(--slds-g-color-brand-base-50, #{$progress-color-border-hover});
  }

  &:focus {
    box-shadow: var(--slds-g-shadow-outset-focus-1, #{$shadow-button-focus});
    outline: 0;
  }
}

&.slds-has-error .slds-progress__marker {

  &,
  &:hover,
  &:focus {
    color: var(--slds-g-color-error-base-40, #{$color-text-error});
    background: var(--slds-g-color-neutral-base-100, #{$progress-color-background});
    border-color: transparent;
    box-shadow: none;
  }

  &:focus {
    box-shadow: var(--slds-g-shadow-outset-focus-1, #{$shadow-button-focus});
    outline: 0;
  }
}

@include deprecate('4.0.0', 'Please use slds-popover_tooltip instead') {

  .slds-tooltip {
    @include popover($color: var(--slds-g-color-brand-base-10, #{$color-background-inverse}));
  }

  .slds-tooltip__body {
    padding: $spacing-x-small $spacing-small;
    font-size: $font-size-2;
    color: var(--slds-g-color-neutral-base-100, #{$color-text-inverse});
  }
}

// scss-lint:disable SelectorDepth
